import React, { useContext } from 'react';
import { View, Text, FlatList, StyleSheet, Platform } from 'react-native';
import HoverableButton from '../components/HoverableButton';
import { AppContext } from '../context/AppContext';
import theme from '../theme';
// Share link removed from Home screen per request

export default function HomeScreen({ navigation }) {
  const { user, groups } = useContext(AppContext);

  const myGroups = groups.filter((g) => g.members.find((m) => m.id === user?.id));

  return (
    <View style={styles.container}>
      <View style={styles.headerRow}>
        <Text style={styles.welcome}>Welcome, {user?.name}</Text>
        <HoverableButton style={styles.createFull} onPress={() => navigation.navigate('CreateGroup')}>
          <Text style={styles.createText}>+ Create Group</Text>
        </HoverableButton>
      </View>

      <View style={styles.pillRow}>
        <HoverableButton style={styles.pillButton} onPress={() => navigation.navigate('CreateGroup')}>
          <Text style={styles.buttonText}>Create Group</Text>
        </HoverableButton>
        <HoverableButton style={styles.pillButton} onPress={() => navigation.navigate('JoinGroup')}>
          <Text style={styles.buttonText}>Join Group</Text>
        </HoverableButton>
        <HoverableButton style={styles.pillButton} onPress={() => navigation.navigate('Calendar')}>
          <Text style={styles.buttonText}>Calendar</Text>
        </HoverableButton>
        <HoverableButton style={styles.pillButton} onPress={() => navigation.navigate('Notes')}>
          <Text style={styles.buttonText}>Notes</Text>
        </HoverableButton>
      </View>

      <Text style={styles.section}>Your Groups</Text>
      <FlatList
        data={myGroups}
        keyExtractor={(item) => item.id}
        renderItem={({ item }) => (
          <HoverableButton style={styles.groupItem} onPress={() => navigation.navigate('Chat', { groupId: item.id })}>
            <View style={styles.groupInner}>
              <View style={styles.accent} />
              <View style={styles.groupContent}>
                <Text style={styles.groupTitle}>{item.title}</Text>
                <Text style={styles.groupMeta}>{item.members.length} members</Text>
              </View>
            </View>
          </HoverableButton>
        )}
        ListEmptyComponent={<Text style={{ color: theme.text }}>You have no groups yet</Text>}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    paddingHorizontal: 24,
    paddingTop: 32,
    paddingBottom: 24,
    backgroundColor: theme.background,
  },
  welcome: {
    fontSize: 24,
    marginBottom: 20,
    color: theme.text,
    fontWeight: '600',
    letterSpacing: 0.2,
    // use a clean sans-serif stack on web, System on native
    fontFamily: Platform.OS === 'web' ? 'system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial' : 'System',
  },
  row: {
    flexDirection: 'row',
    justifyContent: 'flex-start',
    marginBottom: 20,
    flexWrap: 'wrap',
    gap: 10
  },
  section: {
    fontSize: 18,
    marginTop: 24,
    marginBottom: 12,
    color: theme.textPrimary,
    fontWeight: '500'
  },
  groupItem: {
    backgroundColor: '#fff',
    borderRadius: 8,
    padding: 0,
    marginBottom: 12,
    shadowColor: '#000',
    shadowOpacity: 0.03,
    shadowRadius: 6,
    elevation: 0
  },
  groupInner: { flexDirection: 'row', alignItems: 'center' },
  accent: { width: 6, height: '100%', backgroundColor: theme.primary, borderTopLeftRadius: 8, borderBottomLeftRadius: 8 },
  groupContent: { padding: 12, flex: 1 },
  groupTitle: { fontSize: 16, color: theme.textPrimary, fontWeight: '600' },
  groupMeta: { color: theme.textSecondary, marginTop: 4 },
  pillButton: {
    backgroundColor: theme.neutralButton,
    borderRadius: 999,
    paddingVertical: 10,
    paddingHorizontal: 18,
    marginRight: 10,
    minWidth: 110,
    alignItems: 'center',
    marginBottom: 8,
    elevation: 0
  },
  pillRow: { flexDirection: 'row', marginBottom: 12, flexWrap: 'wrap' },
  createFull: {
    backgroundColor: theme.neutralButton,
    borderRadius: 8,
    paddingVertical: 10,
    paddingHorizontal: 14,
    alignItems: 'center',
    justifyContent: 'center'
  },
  createText: {
    color: theme.text,
    fontWeight: '600'
  },
  buttonText: {
    color: theme.buttonText,
    fontWeight: '600',
    fontSize: 14,
    fontFamily: Platform.OS === 'web' ? 'system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial' : 'System'
  }
});
